body.script:
let clickCount = 0;
const noBtn = document.getElementById('noBtn');
const yesBtn = document.getElementById('yesBtn');
const questionText = document.getElementById('questionText');
const mainGif = document.getElementById('mainGif');
const btnGroup = document.getElementById('btnGroup');

// ငြင်းမယ် ခလုတ်ကို ဟိုပြေးဒီပြေးလုပ်မယ့် function
function moveButton() {
    if (clickCount < 6) {
        // Screen ရဲ့ random နေရာကို ရွှေ့မယ် (Container ထဲကနေ လွတ်အောင်)
        const x = Math.random() * (window.innerWidth - noBtn.offsetWidth - 20);
        const y = Math.random() * (window.innerHeight - noBtn.offsetHeight - 20);

        noBtn.style.position = 'fixed';
        noBtn.style.left = x + 'px';
        noBtn.style.top = y + 'px';

        clickCount++;
    } else if (clickCount === 6) {
        // ၇ ခါမြောက်မှာ ခလုတ် ၂ ခုလုံးကို လက်ခံပါတယ် ပြောင်းပစ်မယ်
        questionText.innerHTML = "မောလှပီနော်... လက်ခံလိုက်တော့ 🥺❤️";
        mainGif.src = "https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExbW80N3gwdXp3Nms3N3Nnd3F1ZXF6M3V5N3N0ZDRpZ3FwZHBpaWh3NCZlcD12MV9pbnRlcm5hbF9naWZfYnlfaWQmY3Q9cw/K706nsZ6z6Nmo0SCD9/giphy.gif"; // မောသွားတဲ့ပုံပြောင်း

        // No button ကို Yes Button အဖြစ် ပြောင်းလဲခြင်း
        noBtn.innerHTML = "လက်ခံပါတယ်ရှင့် 🥰";
        noBtn.style.position = 'static'; // မပြေးတော့အောင် ပုံမှန်နေရာ ပြန်ထား
        noBtn.style.backgroundColor = '#ff4d6d';

        // ခလုတ်နှိပ်ရင် ချက်ချင်း အောင်မြင်တဲ့ဆီ သွားအောင်လုပ်မယ်
        noBtn.onmouseover = null; 
        noBtn.onclick = accepted;

        clickCount++;
    }
}

// လက်ခံလိုက်တဲ့အချိန်မှာ ပြမယ့် အလန်းစား Animation
function accepted() {
    questionText.innerHTML = "Yesss! ပျော်လိုက်တာ ရင်ခုန်လိုက်ရတာဗျာ... 💖✨";
    mainGif.src = "https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExM2NuM2gyODN2Y3Y0Y3RmMms3M3pxbnd6bXRwZzBpMGk0Z3Nxb2pxOCZlcD12MV9pbnRlcm5hbF9naWZfYnlfaWQmY3Q9cw/G7LkW8Bvscz5Cq4h2E/giphy.gif"; // ပျော်နေတဲ့ပုံ

    // ခလုတ်တွေကို ဖျောက်လိုက်မယ်
    btnGroup.style.display = 'none';

    // Heart Animation တွေ မိုးရွာသလို ကျလာအောင် လုပ်မယ်
    for (let i = 0; i < 50; i++) {
        setTimeout(createHeart, i * 100);
    }
}

// နှလုံးသားပုံလေးတွေ ဖန်တီးပေးတဲ့ function
function createHeart() {
    const heart = document.createElement('div');
    heart.classList.add('heart');
    heart.style.left = Math.random() * 100 + "vw";
    heart.style.animationDuration = Math.random() * 2 + 3 + "s"; // 3s မှ 5s အတွင်း ရွေ့မယ်
    heart.style.width = heart.style.height = Math.random() * 15 + 10 + "px"; // Size စုံအောင်

    document.body.appendChild(heart);

    // ပြီးရင် ဖျက်ပစ်မယ် memory မပြည့်အောင်
    setTimeout(() => {
        heart.remove();
    }, 4000);
}
